    expect(result).toBeNull();
  });
});

describe('canEnrollNewCourse', () => {
  const mockStudentId = '507f1f77bcf86cd799439013';

  it('returns true when no active enrollments', async () => {
    mockCourseStudentCountDocuments.mockResolvedValue(0);
    const result = await service.canEnrollNewCourse(mockStudentId);
    expect(result).toBe(true);
  });

  it('returns false when active enrollments exist', async () => {
    mockCourseStudentCountDocuments.mockResolvedValue(1);
    const result = await service.canEnrollNewCourse(mockStudentId);
    expect(result).toBe(false);
  });

  it('excludes specific enrollment when excludeEnrollmentId provided', async () => {
    const excludeId = '507f1f77bcf86cd799439014';
    mockCourseStudentCountDocuments.mockResolvedValue(0);
    await service.canEnrollNewCourse(mockStudentId, excludeId);
    expect(mockCourseStudentCountDocuments).toHaveBeenCalledWith(
      expect.objectContaining({
        _id: { $ne: expect.any(mongoose.Types.ObjectId) },
      })
    );
  });
});

